const { ethers } = require('ethers');

const PRIVATE_KEY = '0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80';
const RPC_URL = 'https://eth-mainnet.g.alchemy.com/v2/your-api-key';
const RECIPIENT_ADDRESS = '0x742d35Cc6634C0532925a3b844Bc9e7595f0bEb';

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

async function sendETH(toAddress, amountInEther) {
    try {
        const tx = {
            to: toAddress,
            value: ethers.parseEther(amountInEther.toString()),
            gasLimit: 21000,
        };
        
        const transaction = await wallet.sendTransaction(tx);
        console.log('Transaction hash:', transaction.hash);
        
        const receipt = await transaction.wait();
        console.log('Transaction confirmed in block:', receipt.blockNumber);
        
        return receipt;
    } catch (error) {
        console.error('Error sending ETH:', error);
        throw error;
    }
}

async function getBalance(address) {
    const balance = await provider.getBalance(address);
    return ethers.formatEther(balance);
}

async function interactWithContract(contractAddress, abi, functionName, params = [], value = '0') {
    try {
        const contract = new ethers.Contract(contractAddress, abi, wallet);
        
        const options = {};
        if (value !== '0') {
            options.value = ethers.parseEther(value);
        }
        
        const tx = await contract[functionName](...params, options);
        console.log('Transaction hash:', tx.hash);
        
        const receipt = await tx.wait();
        console.log('Transaction confirmed:', receipt.transactionHash);
        
        return receipt;
    } catch (error) {
        console.error('Error interacting with contract:', error);
        throw error;
    }
}

async function readContract(contractAddress, abi, functionName, params = []) {
    try {
        const contract = new ethers.Contract(contractAddress, abi, provider);
        const result = await contract[functionName](...params);
        return result;
    } catch (error) {
        console.error('Error reading contract:', error);
        throw error;
    }
}

async function deployContract(abi, bytecode, constructorArgs = []) {
    try {
        const factory = new ethers.ContractFactory(abi, bytecode, wallet);
        const contract = await factory.deploy(...constructorArgs);
        await contract.waitForDeployment();
        
        const address = await contract.getAddress();
        console.log('Contract deployed at:', address);
        
        return { contract, address };
    } catch (error) {
        console.error('Error deploying contract:', error);
        throw error;
    }
}

async function sendERC20Token(tokenAddress, toAddress, amount) {
    const erc20ABI = [
        'function transfer(address to, uint256 amount) returns (bool)',
        'function balanceOf(address account) view returns (uint256)',
        'function decimals() view returns (uint8)'
    ];
    
    try {
        const tokenContract = new ethers.Contract(tokenAddress, erc20ABI, wallet);
        const decimals = await tokenContract.decimals();
        const amountInWei = ethers.parseUnits(amount.toString(), decimals);
        
        const tx = await tokenContract.transfer(toAddress, amountInWei);
        console.log('Token transfer hash:', tx.hash);
        
        const receipt = await tx.wait();
        console.log('Token transfer confirmed:', receipt.transactionHash);
        
        return receipt;
    } catch (error) {
        console.error('Error sending ERC20 token:', error);
        throw error;
    }
}

async function estimateGas(toAddress, data = '0x', value = '0') {
    try {
        const gasEstimate = await provider.estimateGas({
            to: toAddress,
            data: data,
            value: ethers.parseEther(value),
            from: wallet.address
        });
        
        return gasEstimate.toString();
    } catch (error) {
        console.error('Error estimating gas:', error);
        throw error;
    }
}

async function signMessage(message) {
    try {
        const signature = await wallet.signMessage(message);
        return signature;
    } catch (error) {
        console.error('Error signing message:', error);
        throw error;
    }
}

async function sendRawTransaction(signedTx) {
    try {
        const tx = await provider.broadcastTransaction(signedTx);
        console.log('Raw transaction hash:', tx.hash);
        
        const receipt = await tx.wait();
        return receipt;
    } catch (error) {
        console.error('Error sending raw transaction:', error);
        throw error;
    }
}

async function batchTransactions(transactions) {
    const results = [];
    
    for (const tx of transactions) {
        try {
            const result = await wallet.sendTransaction(tx);
            const receipt = await result.wait();
            results.push({ success: true, receipt });
        } catch (error) {
            results.push({ success: false, error: error.message });
        }
    }
    
    return results;
}

async function approveERC20(tokenAddress, spenderAddress, amount) {
    const erc20ABI = [
        'function approve(address spender, uint256 amount) returns (bool)',
        'function decimals() view returns (uint8)'
    ];
    
    try {
        const tokenContract = new ethers.Contract(tokenAddress, erc20ABI, wallet);
        const decimals = await tokenContract.decimals();
        const amountInWei = ethers.parseUnits(amount.toString(), decimals);
        
        const tx = await tokenContract.approve(spenderAddress, amountInWei);
        const receipt = await tx.wait();
        
        return receipt;
    } catch (error) {
        console.error('Error approving ERC20:', error);
        throw error;
    }
}

async function getTransactionReceipt(txHash) {
    try {
        const receipt = await provider.getTransactionReceipt(txHash);
        return receipt;
    } catch (error) {
        console.error('Error getting transaction receipt:', error);
        throw error;
    }
}

async function getCurrentGasPrice() {
    const feeData = await provider.getFeeData();
    return {
        gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') : null,
        maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') : null,
        maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') : null
    };
}

